frappe.ui.form.on("WMS ASN", {
  refresh(frm) {
    frm.add_custom_button("Import from Excel", () => {
      new frappe.ui.FileUploader({
        doctype: frm.doctype,
        docname: frm.docname,
        folder: "Home",
        restrictions: { allowed_file_types: [".xlsx"] },
        on_success(file) {
          frappe.call({
            method: "printechs_wms.api.asn_import_ui.import_wms_asn_excel",
            args: {
              file_url: file.file_url,
              submit: 0
            },
            freeze: true,
            freeze_message: "Importing ASN from Excel...",
            callback(r) {
              const res = r.message || {};
              if (res.errors && res.errors.length) {
                frappe.msgprint({
                  title: "Import Completed with Errors",
                  message: "<pre>" + JSON.stringify(res, null, 2) + "</pre>",
                  indicator: "orange"
                });
              } else {
                frappe.msgprint({
                  title: "Import Success",
                  message: `Created ${res.count} ASN(s): ${(res.created || []).join(", ")}`,
                  indicator: "green"
                });
              }
              frm.reload_doc();
            }
          });
        }
      });
    });
  }
});

frappe.ui.form.on("WMS Transfer Order", {
  refresh(frm) {
    frm.add_custom_button("Import TO", () => {
      new frappe.ui.FileUploader({
        doctype: frm.doctype,
        docname: frm.docname,
        folder: "Home",
        restrictions: { allowed_file_types: [".xlsx"] },

        on_success(file) {
          frappe.call({
            // ✅ CHANGE THIS to your real method path (the new header+detail TO import)
            method: "printechs_wms.api.transfer_order_import.import_transfer_order_from_excel",
            args: {
              file_url: file.file_url,
              sheet_name: "WMS Transfer Order", // header sheet
              create_new: 1,                    // 1=create (or update safely), 0=force update existing by name/to_title
              submit: 0
            },
            freeze: true,
            freeze_message: "Importing Transfer Order from Excel...",
            callback(r) {
              const res = r.message || {};

              // show full result if errors exist
              if (res.errors && res.errors.length) {
                frappe.msgprint({
                  title: "Import Completed with Errors",
                  message: "<pre>" + JSON.stringify(res, null, 2) + "</pre>",
                  indicator: "orange"
                });
              } else {
                frappe.msgprint({
                  title: "Import Success",
                  message: `
                    Total Item Lines: ${res.total_items || 0}<br>
                    Created: ${(res.created || []).join(", ") || "-"}<br>
                    Updated: ${(res.updated || []).join(", ") || "-"}<br>
                  `,
                  indicator: "green"
                });
              }

              // If API returns first_to, open it
              if (res.first_to) {
                frappe.set_route("Form", "WMS Transfer Order", res.first_to);
              } else {
                frm.reload_doc();
              }
            }
          });
        }
      });
    });
  }
});

frappe.ui.form.on("Item", {
  refresh(frm) {
    if (frm.is_new()) return;

    frm.add_custom_button(__("WMS Stock by Location / Carton"), async () => {
      const d = await frappe.prompt(
        [
          {
            fieldname: "location",
            fieldtype: "Data",   // ✅ FIXED (was Link)
            label: "Bin Location",
            reqd: 0
          },
          {
            fieldname: "carton_id",
            fieldtype: "Data",
            label: "Carton ID",
            reqd: 0
          },
          {
            fieldname: "show_zero",
            fieldtype: "Check",
            label: "Include Zero Qty",
            default: 0
          }
        ],
        __("Filter WMS Stock"),
        __("Open")
      );

      const filters = {
        item_code: frm.doc.item_code
      };

      if (d.location) {
        filters.location = d.location;   // fieldname in WMS Stock Balance
      }

      if (d.carton_id) {
        filters.carton = d.carton_id;
      }

      if (!d.show_zero) {
        filters.qty = [">", 0];
      }

      frappe.set_route("List", "WMS Stock Balance", filters);
    });
  }
});

frappe.ui.form.on("Item", {
  refresh(frm) {
    if (frm.is_new()) return;
    frm.trigger("wms_attach_stock_levels_drilldown");
  },

  wms_attach_stock_levels_drilldown(frm) {
    let attempts = 0;

    const timer = setInterval(() => {
      attempts++;

      // Find title "Stock Levels" safely
      const $title = $(
        "h3:contains('Stock Levels'), h4:contains('Stock Levels'), div:contains('Stock Levels')"
      ).filter(function () {
        const t = ($(this).text() || "").trim();
        return t === "Stock Levels";
      }).first();

      if (!$title.length) {
        if (attempts >= 12) clearInterval(timer);
        return;
      }

      // Find the container/card that holds the Stock Levels rows
      const $block = $title.closest(".frappe-card, .form-dashboard-section, .section-body, .widget, .form-section");

      if (!$block.length) {
        if (attempts >= 12) clearInterval(timer);
        return;
      }

      // Insert drilldown panel after Stock Levels block
      if ($("#wms_drilldown_panel").length === 0) {
        const panel = $(`
          <div id="wms_drilldown_panel" class="frappe-card" style="margin-top:12px; padding:12px;">
            <div style="display:flex; justify-content:space-between; align-items:center;">
              <b>WMS Stock Drilldown</b>
              <span class="text-muted" id="wms_drilldown_title">Click a Warehouse row above</span>
            </div>
            <div id="wms_drilldown_body" style="margin-top:10px;">
              <div class="text-muted">No warehouse selected.</div>
            </div>
          </div>
        `);
        $block.after(panel);
      }

      // Remove previous handler to avoid duplicates
      $block.off("click.wms");

      // IMPORTANT: make handler async so we can use await
      $block.on("click.wms", "a", async (e) => {
        const warehouse_name = (e.target && e.target.innerText) ? e.target.innerText.trim() : "";
        if (!warehouse_name) return;

        // Only respond to warehouse-like strings
        if (!warehouse_name.includes(" - ")) return;

        e.preventDefault();
        e.stopPropagation();

        $("#wms_drilldown_title").text(`Warehouse: ${warehouse_name}`);
        $("#wms_drilldown_body").html(`<div class="text-muted">Loading WMS stock...</div>`);

        try {
          const resp = await frappe.call({
            method: "printechs_wms.api.wms_stock_drilldown.get_item_location_carton_balance",
            args: {
              item_code: frm.doc.item_code,
              warehouse: warehouse_name, // will filter only if you have warehouse column in WMS Stock Balance
              company: frm.doc.company || null,
              limit: 500
            }
          });

          const rows = (resp.message && resp.message.rows) ? resp.message.rows : [];

          if (!rows.length) {
            $("#wms_drilldown_body").html(
              `<div class="text-muted">No WMS stock found for this item (or warehouse mapping not available).</div>`
            );
            return;
          }

          const esc = (v) => frappe.utils.escape_html(String(v ?? ""));
          const n = (v) => (v === null || v === undefined ? 0 : Number(v) || 0);

          let html = `
            <div style="overflow:auto;">
              <table class="table table-bordered table-hover">
                <thead>
                  <tr>
                    <th>Location ID</th>
                    <th>Carton ID</th>
                    <th class="text-right">Balance</th>
                    <th class="text-right">Reserved</th>
                    <th class="text-right">Available</th>
                    <th>Last Txn</th>
                  </tr>
                </thead>
                <tbody>
          `;

          rows.forEach(r => {
            html += `
              <tr>
                <td>${esc(r.location || "")}</td>
                <td>${esc(r.carton || "")}</td>
                <td class="text-right"><b>${esc(n(r.balance))}</b></td>
                <td class="text-right">${esc(n(r.reserved))}</td>
                <td class="text-right"><b>${esc(n(r.available))}</b></td>
                <td>${esc(r.last_txn_datetime || "")}</td>
              </tr>
            `;
          });

          html += `</tbody></table></div>`;
          $("#wms_drilldown_body").html(html);

        } catch (err) {
          console.error(err);
          $("#wms_drilldown_body").html(`<div class="text-danger">Failed to load WMS stock. Check server logs.</div>`);
        }
      });

      clearInterval(timer);
    }, 700);
  }
});

frappe.ui.form.on('WMS Cycle Count Batch', {
  refresh(frm) {
    if (frm.is_new()) return;

    // Preview button
    if (frm.doc.status !== "Posted") {
      frm.add_custom_button("Load Actual Stock Preview", () => {
        frappe.call({
          method: "printechs_wms.api.cycle_count_batch.load_actual_stock_preview",
          args: { batch_name: frm.doc.name },
          freeze: true,
          callback: (r) => {
            if (r.message && r.message.ok) {
              frappe.msgprint(`Preview done. Updated lines: ${r.message.updated_lines}, Summary rows: ${r.message.summary_rows}`);
              frm.reload_doc();
            } else {
              frappe.msgprint(JSON.stringify(r.message || r, null, 2));
            }
          }
        });
      });
    }

    // Confirm & Post button
    if (frm.doc.status === "Previewed") {
      frm.add_custom_button("Confirm & Post Batch", () => {
        frappe.confirm(
          "This will update WMS Stock Balance and (optionally) create Stock Reconciliation. Continue?",
          () => {
            frappe.call({
              method: "printechs_wms.api.cycle_count_batch.confirm_and_post_batch",
              args: { batch_name: frm.doc.name, create_stock_reconciliation: 1 },
              freeze: true,
              callback: (r) => {
                if (r.message && r.message.ok) {
                  frappe.msgprint(`Posted. Updated balances: ${r.message.updated_balances}. SR: ${r.message.stock_reconciliation || "Not created"}`);
                  frm.reload_doc();
                } else {
                  frappe.msgprint(JSON.stringify(r.message || r, null, 2));
                }
              }
            });
          }
        );
      }).addClass("btn-primary");
    }
  }
});

// Client Script for WMS Cycle Count Batch
// In ERPNext: Customize Form → WMS Cycle Count Batch → Add Client Script (or paste into existing script).
// Buttons: Export Valuation Template, Upload Valuation File (Create Opening SR), Confirm & Post Batch.

frappe.ui.form.on("WMS Cycle Count Batch", {
  refresh(frm) {
    const status = frm.doc.status || "Draft";
    const isDraft = frm.doc.docstatus === 0;

    // -----------------------------
    // 1) Export valuation template
    // -----------------------------
    if (isDraft && ["Draft", "Previewed"].includes(status)) {
      frm.add_custom_button(__("Export Valuation Template"), () => {
        frappe.call({
          method: "printechs_wms.api.cycle_count_batch.export_opening_valuation_template",
          args: { batch_name: frm.doc.name },
          freeze: true,
          freeze_message: __("Generating Excel..."),
          callback: (r) => {
            const m = r.message || {};
            if (!m.ok) {
              const msg = (m.exc_type && m._server_messages) ? (m._server_messages || m.message || __("Export failed.")) : (m.message || __("Export failed."));
              frappe.msgprint({ title: __("Error"), message: msg, indicator: "red" });
              return;
            }
            frappe.msgprint({
              title: __("Template Generated"),
              message: __(
                `Items: <b>${m.item_count}</b><br>File: <a href="${m.file_url}" target="_blank">${m.file_name}</a>`
              ),
              indicator: "green",
            });
          },
        });
      }).addClass("btn-primary");
    }

    // -----------------------------
    // 2) Upload valuation file -> create Opening SR
    // -----------------------------
    if (isDraft && ["Draft", "Previewed"].includes(status)) {
      frm.add_custom_button(__("Upload Valuation File (Create Opening SR)"), () => {
        const company = frm.doc.company || "";
        frappe.prompt(
          [
            {
              fieldname: "valuation_file",
              fieldtype: "Attach",
              label: __("Valuation Excel File"),
              reqd: 1,
              description: __("Upload the filled Excel generated from 'Export Valuation Template'."),
            },
            {
              fieldname: "difference_account",
              fieldtype: "Link",
              options: "Account",
              label: __("Difference Account"),
              reqd: 1,
              description: __("Must be an Asset or Liability account. Click the field to search and select."),
              get_query: () => ({
                filters: [
                  ["Account", "root_type", "in", ["Asset", "Liability"]],
                  ["Account", "is_group", "=", 0],
                  ["Account", "company", "=", company],
                ],
              }),
            },
            {
              fieldname: "create_opening_sr",
              fieldtype: "Check",
              label: __("Create Opening Stock Reconciliation"),
              default: 1,
              read_only: 1,
            },
          ],
          (values) => {
            if (!values || !values.valuation_file) return;
            if (!values.difference_account) {
              frappe.msgprint({ title: __("Required"), message: __("Please select Difference Account."), indicator: "orange" });
              return;
            }
            frappe.call({
              method: "printechs_wms.api.cycle_count_batch.upload_opening_valuation_file",
              args: {
                file_url: values.valuation_file,
                batch_name: frm.doc.name,
                difference_account: values.difference_account,
              },
              freeze: true,
              freeze_message: __("Creating Opening Stock Reconciliation..."),
              callback: (r) => {
                const m = r.message || {};
                if (!m.ok) {
                  const msg = (m.exc_type && m._server_messages) ? (m._server_messages || m.message || __("Upload failed.")) : (m.message || __("Upload failed."));
                  frappe.msgprint({ title: __("Error"), message: msg, indicator: "red" });
                  return;
                }
                frappe.msgprint({
                  title: __("Opening Stock Created"),
                  message: __(
                    `SR: <b>${m.sr}</b><br>Rows: <b>${m.row_count}</b><br>Warehouse: <b>${m.warehouse}</b>`
                  ),
                  indicator: "green",
                });
                frm.reload_doc();
              },
            });
          },
          __("Upload Valuation Excel"),
          __("Upload & Create")
        );
      });
    }

    // -----------------------------
    // 3) Confirm & Post Batch (warehouse posting)
    // -----------------------------
    if (isDraft && ["Draft", "Previewed"].includes(status)) {
      frm.add_custom_button(__("Confirm & Post Batch"), () => {
        frappe.call({
          method: "printechs_wms.api.cycle_count_batch.confirm_and_post_batch",
          args: {
            batch_name: frm.doc.name,
            create_stock_reconciliation: 1,
          },
          freeze: true,
          freeze_message: __("Posting batch..."),
          callback: (r) => {
            const m = r.message || {};
            if (!m.ok) {
              const msg = (r.exc_type && r._server_messages) ? (r._server_messages || r.message || __("Posting failed.")) : (m.message || r.message || __("Posting failed."));
              frappe.msgprint({ title: __("Error"), message: msg, indicator: "red" });
              return;
            }
            frappe.msgprint({
              title: __("Posted"),
              message: __(
                `Batch: <b>${m.batch}</b><br>Updated Balances: <b>${m.updated_balances}</b><br>SR: <b>${m.sr || "N/A"}</b>`
              ),
              indicator: "green",
            });
            frm.reload_doc();
          },
          error: (err) => {
            console.error(err);
            const msg = (err && (err.message || err.exc)) ? (err.message || err.exc) : __("Check server logs / Error Log for details.");
            frappe.msgprint({ title: __("Error"), message: msg, indicator: "red" });
          },
        });
      }).addClass("btn-danger");
    }
  },
});
